package org.apache.commons.csv;
import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.lang.reflect.InvocationTargetException;
import java.lang.reflect.Method;
import java.util.Collections;
import java.util.HashMap;
import java.util.Map;

import org.apache.commons.csv.CSVRecord;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

public class CSVRecordTest {

    private Map<String, Integer> mapping;
    private String[] values;
    private CSVRecord record;

    @BeforeEach
    public void setUp() {
        mapping = new HashMap<>();
        mapping.put("Name", 0);
        mapping.put("Age", 1);
        values = new String[] { "Alice", "30" };
        record = new CSVRecord(values, mapping, null, 1L);
    }

    @Test
    public void testGet_WithValidName() {
        assertEquals("Alice", record.get("Name"));
        assertEquals("30", record.get("Age"));
    }

    @Test
    public void testGet_WithNameNotInMapping() {
        assertNull(record.get("NonExistent"));
    }

    @Test
    public void testGet_WithNullMapping_ThrowsException() throws NoSuchMethodException, SecurityException, IllegalAccessException, IllegalArgumentException, InvocationTargetException {
        // Create CSVRecord with null mapping using reflection (constructor is package-private)
        CSVRecord recordWithNullMapping = createCSVRecordWithNullMapping();

        IllegalStateException thrown = assertThrows(IllegalStateException.class, () -> {
            recordWithNullMapping.get("Name");
        });
        assertEquals(
                "No header mapping was specified, the record values can't be accessed by name",
                thrown.getMessage());
    }

    private CSVRecord createCSVRecordWithNullMapping() {
        // Using reflection to invoke package-private constructor
        try {
            Class<CSVRecord> clazz = CSVRecord.class;
            return clazz.getDeclaredConstructor(String[].class, Map.class, String.class, long.class)
                    .newInstance(new String[] { "Alice", "30" }, null, null, 1L);
        } catch (Exception e) {
            throw new RuntimeException(e);
        }
    }
}
